"use strict";(()=>{(function(){"use strict";document.addEventListener("DOMContentLoaded",()=>{gsap.registerPlugin(ScrollTrigger);const t=document.querySelectorAll(".text-mask");if(!t.length)return;gsap.matchMedia().add({isMobile:"screen and (max-width: 767px)",isDesktop:"screen and (min-width: 768px)"},o=>{const{isMobile:s}=o.conditions;t.forEach(e=>{gsap.set(e,{display:"inline-block"});const a=new SplitType(e,{types:"words"}),i=e.querySelectorAll("em");gsap.set(i,{display:"unset"}),gsap.set(a.words,{yPercent:80,opacity:0,autoAlpha:0});const n=gsap.timeline();n.to(a.words,{ease:r=>1-Math.pow(1-r,4),duration:s?1.5:1,yPercent:0,opacity:1,autoAlpha:1,stagger:.01}),ScrollTrigger.create({trigger:e,markers:!1,start:s?"top 85%":"top 75%",animation:n})})})})})();})();
